#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long powmod(long long a, long long b) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int a[N];
        for (int i = 0; i < N; i++) scanf("%d", &a[i]);
        long long ans = 1;
        for (int mask = 0; mask < (1 << N); mask++) {
            if (__builtin_popcount(mask) == K) {
                int sub[N];
                int idx = 0;
                for (int i = 0; i < N; i++) if (mask & (1 << i)) sub[idx++] = a[i];
                qsort(sub, K, sizeof(int), compare);
                long long prod = 1;
                for (int i = 1; i < K - 1; i++) prod = (prod * sub[i]) % MOD;
                ans = (ans * prod) % MOD;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

