const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;

function powmod(a, b) {
    let res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}

function nextInt() {
    return parseInt(lines[idx++]);
}

function nextIntArray() {
    return lines[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let [N, K] = nextIntArray();
    let a = nextIntArray();
    let ans = 1;
    for (let mask = 0; mask < (1 << N); mask++) {
        if (countBits(mask) == K) {
            let sub = [];
            for (let i = 0; i < N; i++) if ((mask & (1 << i)) != 0) sub.push(a[i]);
            sub.sort((a, b) => a - b);
            let prod = 1;
            for (let i = 1; i < K - 1; i++) prod = (prod * sub[i]) % MOD;
            ans = (ans * prod) % MOD;
        }
    }
    console.log(ans);
}

function countBits(n) {
    let count = 0;
    while (n > 0) {
        count += n & 1;
        n >>= 1;
    }
    return count;
}
